function determineConfidence(
  ratio: number,
  coOccurringPatterns: string[],
  astLevel: boolean,
  hasConflict = false,
): ForensicAssertion["confidence"] {
  if (hasConflict) return "LOW";
  if (astLevel) return "HIGH";
  if (ratio < 0.5) return "LOW";
  if (ratio >= 0.8 && coOccurringPatterns.length >= 2) return "HIGH";
  return "MEDIUM";
}

async function loadRulesForPath(
  projectRoot: string,
  meta: AgentsMeta,
  path: string,
): Promise<LoadedRule[]> {
  const requestedPath = normalizeRulesPath(path);
  const matchedNodes = Object.entries(meta.nodes)
    .filter(([, node]) => minimatch(requestedPath, normalizeRulesPath(node.scope_glob), { dot: true }))
    .sort((left, right) => {
      const priorityDelta = PRIORITY_ORDER[leftNode.priority] - PRIORITY_ORDER[rightNode.priority];
      return priorityDelta !== 0 ? priorityDelta : leftId.localeCompare(rightId);
    });
  return await Promise.all(
    matchedNodes.map(async ([nodeId, node]) => ({
      level: classifyNode(nodeId),
      entry: {
        path: node.file,
        content: await readFile(join(projectRoot, node.file), "utf8"),
      },
    })),
  );
}

replayFrom(afterId: number): BufferedEvent[] {
  const result: BufferedEvent[] = [];
  const total = this.count;
  const start = this.count < this.capacity ? 0 : this.head;
  for (let i = 0; i < total; i++) {
    const entry = this.buf[(start + i) % this.capacity];
    if (entry !== undefined && entry.id > afterId) {
      result.push(entry);
    }
  }
  return result;
}

cacheWatcher.on("change", (relativePath: string) => {
  const normalized = relativePath.replaceAll("\\", "/");
  if (normalized === ".fabric/agents.meta.json") {
    contextCache.invalidate("file_watch", projectRoot);
    clearTimeout(toolListNotifyTimer);
    toolListNotifyTimer = setTimeout(() => {
      notifyAllSessions(sessions, "tools/list_changed");
    }, NOTIFY_DEBOUNCE_MS);
  } else if (normalized === ".fabric/bootstrap/README.md") {
    contextCache.invalidate("file_watch", projectRoot);
    clearTimeout(agentsMdNotifyTimer);
    agentsMdNotifyTimer = setTimeout(() => {
      notifyAllSessions(sessions, "resource_updated", AGENTS_MD_RESOURCE_URI);
    }, NOTIFY_DEBOUNCE_MS);
  }
});

function mergeClaudeStopHook(settingsPath: string, options?: InitOptions): ClaudeSettingsAction {
  // ... 读取并验证现有settings ...
  const hasExistingFabricHook = hasClaudeInitReminderHook(stopHooks);
  if (hasExistingFabricHook && !options?.force) {
    return "skipped";
  }
  const nextStopHooks = hasExistingFabricHook && options?.force
    ? removeClaudeInitReminderHook(stopHooks)
    : [...stopHooks];
  nextStopHooks.push({
    matcher: "*",
    hooks: [{ type: "command", command: CLAUDE_INIT_REMINDER_COMMAND }],
  });
  settings.hooks = { ...hooks, Stop: nextStopHooks };
  writeJsonAtomically(settingsPath, settings);
  return hasExistingFabricHook && options?.force ? "overwritten" : action;
}

void (async () => {
  try {
    const response = await fetch(path, { headers, signal: controller.signal });
    if (!response.ok || response.body === null) {
      notifyCloseOnce(() => { onClose(); });
      return;
    }
    onOpen();
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buf = "";
    while (!closed) {
      const { done, value } = await reader.read();
      if (done) break;
      buf += decoder.decode(value, { stream: true });
      buf = buf.replace(/\r\n/g, "\n");
      let boundary: number;
      while ((boundary = buf.indexOf("\n\n")) >= 0) {
        const block = buf.slice(0, boundary);
        buf = buf.slice(boundary + 2);
        parseSseBlock(block, onEvent);
      }
    }
  } catch {
    // intentionally swallowed
  } finally {
    if (!closed) { notifyCloseOnce(() => { onClose(); }); }
  }
})();
